import React, { useState } from 'react';
import { GraduationCap, Upload, Plus, Edit, Trash2, Users, Star, DollarSign, BookOpen, TrendingUp, BarChart3, PieChart, X, Video, Link, FileVideo, Eye, Play, Save } from 'lucide-react';

const InstructorPage = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showCourseModal, setShowCourseModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [dragActive, setDragActive] = useState(false);
  const [thumbnailDragActive, setThumbnailDragActive] = useState(false);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: '',
    cat: 'development',
    level: 'Beginner',
    time: '',
    instructor: 'Current User',
    img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
    videos: [],
    videoType: 'link',
    newVideoUrl: ''
  });

  const instructorStats = {
    totalCourses: courses.length,
    totalStudents: courses.reduce((sum, course) => sum + course.enrolled, 0),
    totalRevenue: courses.reduce((sum, course) => sum + (course.price * course.enrolled), 0),
    avgRating: courses.length > 0 ? (courses.reduce((sum, course) => sum + parseFloat(course.rating), 0) / courses.length).toFixed(1) : '0.0'
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price) {
      onAddCourse({
        ...courseForm,
        price: parseInt(courseForm.price),
        videoUrl: courseForm.videos.length > 0 ? courseForm.videos[0] : ''
      });
      setCourseForm({
        title: '',
        desc: '',
        price: '',
        cat: 'development',
        level: 'Beginner',
        time: '',
        instructor: 'Current User',
        img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
        videos: [],
        videoType: 'link',
        newVideoUrl: ''
      });
      setShowUploadModal(false);
      alert('Course uploaded successfully!');
    }
  };

  const handleEditSubmit = (e) => {
    e.preventDefault();
    if (courseForm.title && courseForm.desc && courseForm.price && selectedCourse) {
      onUpdateCourse(selectedCourse.id, {
        ...courseForm,
        price: parseInt(courseForm.price),
        videoUrl: courseForm.videos.length > 0 ? courseForm.videos[0] : '',
        videos: courseForm.videos
      });
      setShowEditModal(false);
      setSelectedCourse(null);
      alert('Course updated successfully!');
    }
  };

  const handleDelete = (courseId, courseTitle) => {
    if (window.confirm(`Are you sure you want to delete "${courseTitle}"?`)) {
      onDeleteCourse(courseId);
      alert('Course deleted successfully!');
    }
  };

  const editCourse = (course) => {
    setSelectedCourse(course);
    const existingVideos = [];
    if (course.videoUrl) existingVideos.push(course.videoUrl);
    if (course.videos && Array.isArray(course.videos)) {
      course.videos.forEach(video => {
        if (video && !existingVideos.includes(video)) {
          existingVideos.push(video);
        }
      });
    }
    setCourseForm({
      title: course.title,
      desc: course.desc,
      price: course.price.toString(),
      cat: course.cat,
      level: course.level,
      time: course.time,
      instructor: course.instructor,
      img: course.img,
      videos: existingVideos,
      videoType: 'link',
      newVideoUrl: ''
    });
    setShowEditModal(true);
  };

  const handleVideoUpload = (file) => {
    if (file && file.type.startsWith('video/')) {
      const videoUrl = URL.createObjectURL(file);
      setCourseForm({...courseForm, videos: [...courseForm.videos, videoUrl]});
      alert('Video uploaded successfully!');
    } else {
      alert('Please select a valid video file');
    }
  };

  const handleThumbnailUpload = (file) => {
    if (file && file.type.startsWith('image/')) {
      const imageUrl = URL.createObjectURL(file);
      setCourseForm({...courseForm, img: imageUrl});
      alert('Thumbnail uploaded successfully!');
    } else {
      alert('Please select a valid image file');
    }
  };

  const removeVideo = (index) => {
    const updatedVideos = courseForm.videos.filter((_, i) => i !== index);
    setCourseForm({...courseForm, videos: updatedVideos});
    alert('Video removed successfully!');
  };

  const addVideoUrl = () => {
    if (courseForm.newVideoUrl.trim()) {
      setCourseForm({
        ...courseForm,
        videos: [...courseForm.videos, courseForm.newVideoUrl.trim()],
        newVideoUrl: ''
      });
      alert('Video added successfully!');
    }
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleThumbnailDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setThumbnailDragActive(true);
    } else if (e.type === "dragleave") {
      setThumbnailDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleVideoUpload(e.dataTransfer.files[0]);
    }
  };

  const handleThumbnailDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setThumbnailDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleThumbnailUpload(e.dataTransfer.files[0]);
    }
  };

  const viewCourse = (course) => {
    setSelectedCourse(course);
    setShowCourseModal(true);
  };

  const RevenueChart = () => {
    const data = [20, 35, 45, 30, 55, 40, 65];
    const maxValue = Math.max(...data);

    return (
      <div className="flex items-end justify-between h-20 px-2">
        {data.map((value, index) => (
          <div key={index} className="flex flex-col items-center">
            <div
              className="bg-green-500 rounded-t w-6 transition-all duration-300 hover:bg-green-600"
              style={{ height: `${(value / maxValue) * 100}%` }}
            />
            <span className="text-xs text-gray-500 mt-1">{index + 1}</span>
          </div>
        ))}
      </div>
    );
  };

  const EnrollmentChart = () => {
    const data = [15, 25, 35, 20, 45, 30, 50];
    const maxValue = Math.max(...data);

    return (
      <div className="flex items-end justify-between h-20 px-2">
        {data.map((value, index) => (
          <div key={index} className="flex flex-col items-center">
            <div
              className="bg-blue-500 rounded-t w-6 transition-all duration-300 hover:bg-blue-600"
              style={{ height: `${(value / maxValue) * 100}%` }}
            />
            <span className="text-xs text-gray-500 mt-1">W{index + 1}</span>
          </div>
        ))}
      </div>
    );
  };

  const PerformanceChart = () => {
    const categories = [
      { name: 'Development', percentage: 70, color: 'blue' },
      { name: 'Design', percentage: 45, color: 'green' },
      { name: 'Business', percentage: 60, color: 'yellow' },
      { name: 'AI/Data Science', percentage: 35, color: 'purple' }
    ];

    return (
      <div className="space-y-3">
        {categories.map((category, index) => (
          <div key={index} className="flex justify-between items-center">
            <span className="text-sm font-medium">{category.name}</span>
            <div className="flex items-center space-x-2">
              <div className="w-20 bg-gray-200 rounded-full h-2">
                <div 
                  className={`bg-${category.color}-500 h-2 rounded-full transition-all duration-500`}
                  style={{ width: `${category.percentage}%` }}
                />
              </div>
              <span className="text-xs text-gray-600 w-8">{category.percentage}%</span>
            </div>
          </div>
        ))}
      </div>
    );
  };

  const CourseModal = ({ course, onClose }) => (
    <div className="fixed inset-0 flex items-center justify-center bg-black/50 z-50 p-4">
      <div className="bg-white rounded-xl max-w-4xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="relative">
          <img className="w-full h-48 sm:h-64 object-cover" src={course.img} alt={course.title} />
          <button onClick={onClose} className="absolute top-4 right-4 bg-white/90 text-gray-700 w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition">
            <X className="w-4 h-4" />
          </button>
          <div className="absolute top-4 left-4 bg-green-600 text-white px-3 py-1 rounded-full text-sm font-medium">
            FREE ACCESS - Instructor View
          </div>
        </div>
        <div className="p-6 sm:p-8">
          <div className="flex flex-col sm:flex-row justify-between items-start mb-6 gap-2">
            <h2 className="text-xl sm:text-2xl font-bold text-gray-900">{course.title}</h2>
            <span className="text-xl sm:text-2xl font-bold text-blue-600">₹{course.price.toLocaleString()}</span>
          </div>

          <p className="text-gray-600 mb-6">{course.desc}</p>

          {course.videoUrl && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold mb-3 flex items-center">
                <Video className="w-5 h-5 mr-2 text-blue-600" />
                Course Video
              </h3>
              <div className="bg-gray-100 p-4 rounded-lg">
                <p className="text-sm text-gray-600 mb-2">Video URL: {course.videoUrl}</p>
                <button className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition flex items-center">
                  <Play className="w-4 h-4 mr-2" />
                  Play Video
                </button>
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Instructor</div>
              <div className="font-semibold text-gray-900">{course.instructor}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Duration</div>
              <div className="font-semibold text-gray-900">{course.time}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Level</div>
              <div className="font-semibold text-gray-900">{course.level}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Students</div>
              <div className="font-semibold text-gray-900">{course.enrolled.toLocaleString()}</div>
            </div>
          </div>

          <div className="bg-blue-50 p-4 rounded-lg mb-6">
            <h3 className="font-semibold text-blue-800 mb-2">Course Content (Instructor Access)</h3>
            <div className="space-y-2">
              <div className="flex items-center justify-between p-2 bg-white rounded">
                <span className="text-sm">1. Introduction to {course.title}</span>
                <span className="text-xs text-green-600">✓ Available</span>
              </div>
              <div className="flex items-center justify-between p-2 bg-white rounded">
                <span className="text-sm">2. Core Concepts and Fundamentals</span>
                <span className="text-xs text-green-600">✓ Available</span>
              </div>
              <div className="flex items-center justify-between p-2 bg-white rounded">
                <span className="text-sm">3. Practical Examples and Projects</span>
                <span className="text-xs text-green-600">✓ Available</span>
              </div>
              <div className="flex items-center justify-between p-2 bg-white rounded">
                <span className="text-sm">4. Advanced Topics and Best Practices</span>
                <span className="text-xs text-green-600">✓ Available</span>
              </div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-4">
            <button className="flex-1 bg-green-600 hover:bg-green-700 text-white font-semibold py-3 px-6 rounded-lg transition">
              <Eye className="w-4 h-4 inline mr-2" />
              Full Course Access (Instructor)
            </button>
            <button 
              onClick={() => handleDelete(course.id, course.title)}
              className="bg-red-600 hover:bg-red-700 text-white px-6 py-3 rounded-lg transition"
            >
              <Trash2 className="w-4 h-4 inline mr-2" />
              Delete Course
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  const EditModal = () => (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl max-w-3xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="p-6 border-b flex justify-between items-center">
          <h2 className="text-xl font-bold text-gray-900">Edit Course</h2>
          <button onClick={() => setShowEditModal(false)} className="text-gray-500 hover:text-gray-700 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>
        <form onSubmit={handleEditSubmit} className="p-6 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Course Title *</label>
              <input 
                type="text" 
                value={courseForm.title}
                onChange={(e) => setCourseForm({...courseForm, title: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                placeholder="Enter course title" 
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Price (₹) *</label>
              <input 
                type="number" 
                value={courseForm.price}
                onChange={(e) => setCourseForm({...courseForm, price: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                placeholder="99" 
                min="1"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Description *</label>
            <textarea 
              value={courseForm.desc}
              onChange={(e) => setCourseForm({...courseForm, desc: e.target.value})}
              className="w-full border border-gray-300 rounded-lg px-3 py-2 h-24 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
              placeholder="Course description"
              required
            ></textarea>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Duration</label>
              <input 
                type="text" 
                value={courseForm.time}
                onChange={(e) => setCourseForm({...courseForm, time: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                placeholder="8h 30m" 
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
              <select 
                value={courseForm.cat}
                onChange={(e) => setCourseForm({...courseForm, cat: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
              >
                <option value="development">Development</option>
                <option value="design">Design</option>
                <option value="business">Business</option>
                <option value="ai">AI/Data Science</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Level</label>
              <select 
                value={courseForm.level}
                onChange={(e) => setCourseForm({...courseForm, level: e.target.value})}
                className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
              >
                <option value="Beginner">Beginner</option>
                <option value="Intermediate">Intermediate</option>
                <option value="Advanced">Advanced</option>
              </select>
            </div>
          </div>

          {/* Video Management Section */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
              <Video className="w-5 h-5 mr-2 text-blue-600" />
              Course Videos Management ({courseForm.videos.length} videos)
            </h3>

            {/* Existing Videos */}
            {courseForm.videos.length > 0 && (
              <div className="mb-4">
                <h4 className="text-sm font-medium text-gray-700 mb-2">Current Videos</h4>
                <div className="space-y-2">
                  {courseForm.videos.map((video, index) => (
                    <div key={index} className="bg-white p-3 rounded-lg border flex items-center justify-between">
                      <div className="flex-1">
                        <p className="text-sm font-medium text-gray-700">Video {index + 1}</p>
                        <p className="text-xs text-gray-500 truncate max-w-md">{video}</p>
                      </div>
                      <div className="flex space-x-2">
                        <button
                          type="button"
                          className="bg-blue-600 text-white px-2 py-1 rounded text-xs hover:bg-blue-700 transition flex items-center"
                        >
                          <Play className="w-3 h-3 mr-1" />
                          Preview
                        </button>
                        <button
                          type="button"
                          onClick={() => removeVideo(index)}
                          className="bg-red-600 text-white px-2 py-1 rounded text-xs hover:bg-red-700 transition"
                        >
                          Remove
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Add New Video */}
            <div className="border-t pt-4">
              <h4 className="text-sm font-medium text-gray-700 mb-3">Add New Video</h4>
              <div className="flex space-x-4 mb-4">
                <button
                  type="button"
                  onClick={() => setCourseForm({...courseForm, videoType: 'link'})}
                  className={`flex items-center px-4 py-2 rounded-lg border transition-colors ${
                    courseForm.videoType === 'link' 
                      ? 'bg-blue-600 text-white border-blue-600' 
                      : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                  }`}
                >
                  <Link className="w-4 h-4 mr-2" />
                  Add Video Link
                </button>
                <button
                  type="button"
                  onClick={() => setCourseForm({...courseForm, videoType: 'upload'})}
                  className={`flex items-center px-4 py-2 rounded-lg border transition-colors ${
                    courseForm.videoType === 'upload' 
                      ? 'bg-blue-600 text-white border-blue-600' 
                      : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                  }`}
                >
                  <FileVideo className="w-4 h-4 mr-2" />
                  Upload Video
                </button>
              </div>

              {courseForm.videoType === 'link' ? (
                <div className="flex space-x-2">
                  <input 
                    type="url" 
                    value={courseForm.newVideoUrl}
                    onChange={(e) => setCourseForm({...courseForm, newVideoUrl: e.target.value})}
                    className="flex-1 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                    placeholder="https://dropbox.com/s/xyz/video.mp4 or YouTube/Vimeo link" 
                  />
                  <button
                    type="button"
                    onClick={addVideoUrl}
                    className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition flex items-center"
                  >
                    <Plus className="w-4 h-4 mr-1" />
                    Add
                  </button>
                </div>
              ) : (
                <div 
                  className={`border-2 border-dashed rounded-lg p-6 text-center transition-colors cursor-pointer ${
                    dragActive 
                      ? 'border-blue-500 bg-blue-50' 
                      : 'border-gray-300 hover:border-gray-400'
                  }`}
                  onDragEnter={handleDrag}
                  onDragLeave={handleDrag}
                  onDragOver={handleDrag}
                  onDrop={handleDrop}
                  onClick={() => document.getElementById('editVideoUpload').click()}
                >
                  <input 
                    type="file" 
                    accept="video/*" 
                    onChange={(e) => e.target.files[0] && handleVideoUpload(e.target.files[0])}
                    className="hidden" 
                    id="editVideoUpload"
                  />
                  <FileVideo className="w-8 h-8 mx-auto mb-2 text-gray-400" />
                  <p className="text-gray-600 font-medium">
                    {dragActive ? 'Drop video here' : 'Click to upload or drag and drop'}
                  </p>
                  <p className="text-sm text-gray-500 mt-1">MP4, MOV, AVI up to 500MB</p>
                </div>
              )}
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button type="submit" className="flex-1 bg-blue-600 text-white py-3 rounded-lg hover:bg-blue-700 font-medium transition-colors flex items-center justify-center">
              <Save className="w-4 h-4 mr-2" />
              Update Course
            </button>
            <button 
              type="button"
              onClick={() => setShowEditModal(false)}
              className="px-6 bg-gray-200 text-gray-700 py-3 rounded-lg hover:bg-gray-300 transition-colors"
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center">
              <GraduationCap className="w-8 h-8 text-blue-600 mr-3" />
              <h1 className="text-2xl font-bold text-gray-900">Instructor Dashboard</h1>
            </div>
            <button 
              onClick={() => setShowUploadModal(true)}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center hover:bg-blue-700 transition-colors"
            >
              <Plus className="w-4 h-4 mr-2" />
              New Course
            </button>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-blue-500 hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-1">Total Courses</p>
                <p className="text-3xl font-bold text-blue-600">{instructorStats.totalCourses}</p>
                <p className="text-xs text-green-600 mt-1">+2 this month</p>
              </div>
              <div className="bg-blue-100 p-3 rounded-full">
                <BookOpen className="w-8 h-8 text-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-green-500 hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-1">Total Students</p>
                <p className="text-3xl font-bold text-green-600">{instructorStats.totalStudents.toLocaleString()}</p>
                <p className="text-xs text-green-600 mt-1">+12% growth</p>
              </div>
              <div className="bg-green-100 p-3 rounded-full">
                <Users className="w-8 h-8 text-green-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-yellow-500 hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-1">Total Revenue</p>
                <p className="text-3xl font-bold text-yellow-600">₹{instructorStats.totalRevenue.toLocaleString()}</p>
                <p className="text-xs text-green-600 mt-1">+8% this month</p>
              </div>
              <div className="bg-yellow-100 p-3 rounded-full">
                <DollarSign className="w-8 h-8 text-yellow-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-purple-500 hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-1">Avg Rating</p>
                <p className="text-3xl font-bold text-purple-600">{instructorStats.avgRating}</p>
                <p className="text-xs text-green-600 mt-1">Excellent!</p>
              </div>
              <div className="bg-purple-100 p-3 rounded-full">
                <Star className="w-8 h-8 text-purple-600" />
              </div>
            </div>
          </div>
        </div>

        {/* Charts Section */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-800">Revenue Trend</h3>
              <div className="flex items-center text-green-600">
                <TrendingUp className="w-5 h-5 mr-1" />
                <span className="text-sm font-medium">+15%</span>
              </div>
            </div>
            <RevenueChart />
            <p className="text-sm text-gray-600 mt-3 text-center">Last 7 days performance</p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-800">Weekly Enrollments</h3>
              <div className="flex items-center text-blue-600">
                <BarChart3 className="w-5 h-5 mr-1" />
                <span className="text-sm font-medium">+8%</span>
              </div>
            </div>
            <EnrollmentChart />
            <p className="text-sm text-gray-600 mt-3 text-center">Weekly enrollment trends</p>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-800">Course Performance</h3>
              <PieChart className="w-5 h-5 text-purple-600" />
            </div>
            <PerformanceChart />
            <p className="text-sm text-gray-600 mt-3 text-center">Category-wise performance</p>
          </div>
        </div>

        {/* Tabs Section */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
          <div className="border-b border-gray-200">
            <nav className="flex space-x-8 px-6">
              {[
                { key: 'dashboard', label: 'Dashboard', icon: BarChart3 },
                { key: 'courses', label: 'My Courses', icon: BookOpen },
                { key: 'analytics', label: 'Analytics', icon: TrendingUp }
              ].map(tab => (
                <button
                  key={tab.key}
                  onClick={() => setActiveTab(tab.key)}
                  className={`py-4 px-1 border-b-2 font-medium text-sm flex items-center transition-colors ${
                    activeTab === tab.key 
                      ? 'border-blue-500 text-blue-600' 
                      : 'border-transparent text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <tab.icon className="w-4 h-4 mr-2" />
                  {tab.label}
                </button>
              ))}
            </nav>
          </div>

          <div className="p-6">
            {activeTab === 'courses' && (
              <div>
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-semibold text-gray-800">My Courses ({courses.length})</h3>
                  <div className="text-sm text-gray-600">
                    Total Revenue: ₹{instructorStats.totalRevenue.toLocaleString()}
                  </div>
                </div>
                <div className="space-y-4">
                  {courses.map(course => (
                    <div key={course.id} className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition-colors">
                      <div className="flex justify-between items-center">
                        <div className="flex items-center space-x-4">
                          <img src={course.img} alt={course.title} className="w-16 h-16 rounded-lg object-cover" />
                          <div>
                            <h4 className="font-semibold text-gray-900">{course.title}</h4>
                            <div className="flex items-center space-x-4 text-sm text-gray-600 mt-1">
                              <span className="flex items-center">
                                <Users className="w-4 h-4 mr-1" />
                                {course.enrolled} students
                              </span>
                              <span className="flex items-center">
                                <Star className="w-4 h-4 mr-1 text-yellow-400" />
                                {course.rating}
                              </span>
                              <span className="flex items-center font-medium text-blue-600">
                                <DollarSign className="w-4 h-4 mr-1" />
                                ₹{course.price} per course
                              </span>
                              <span className="text-green-600 font-medium">
                                Total: ₹{(course.price * course.enrolled).toLocaleString()}
                              </span>
                              {course.videoUrl && (
                                <span className="flex items-center text-purple-600">
                                  <Video className="w-4 h-4 mr-1" />
                                  Video
                                </span>
                              )}
                            </div>
                            <div className="flex items-center mt-2">
                              <span className="px-2 py-1 rounded-full text-xs bg-green-100 text-green-800">
                                Published
                              </span>
                              <span className="ml-2 text-xs text-gray-500">
                                Category: {course.cat}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex space-x-2">
                          <button 
                            onClick={() => viewCourse(course)}
                            className="p-2 text-gray-600 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                          >
                            <Eye className="w-4 h-4" />
                          </button>
                          <button 
                            onClick={() => editCourse(course)}
                            className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                          >
                            <Edit className="w-4 h-4" />
                          </button>
                          <button 
                            onClick={() => handleDelete(course.id, course.title)}
                            className="p-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'dashboard' && (
              <div>
                <h3 className="text-xl font-semibold text-gray-800 mb-6">Recent Activity</h3>
                <div className="space-y-4">
                  {[
                    { type: 'success', message: 'Course edited and video updated successfully', time: '1 hour ago' },
                    { type: 'info', message: 'Course received new enrollment', time: '4 hours ago' },
                    { type: 'warning', message: 'Payment of ₹15,000 received', time: '1 day ago' },
                    { type: 'info', message: 'Course rating updated to 4.8', time: '2 days ago' }
                  ].map((activity, index) => (
                    <div key={index} className="flex items-center p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors">
                      <div className={`w-3 h-3 rounded-full mr-4 ${
                        activity.type === 'success' ? 'bg-green-500' :
                        activity.type === 'info' ? 'bg-blue-500' :
                        activity.type === 'warning' ? 'bg-yellow-500' : 'bg-gray-500'
                      }`} />
                      <div className="flex-1">
                        <span className="text-sm font-medium text-gray-900">{activity.message}</span>
                        <p className="text-xs text-gray-500 mt-1">{activity.time}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'analytics' && (
              <div>
                <h3 className="text-xl font-semibold text-gray-800 mb-6">Detailed Analytics</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  <div className="bg-gradient-to-r from-green-50 to-green-100 p-6 rounded-lg border border-green-200">
                    <h4 className="font-semibold text-green-800 mb-2">Monthly Revenue</h4>
                    <div className="text-3xl font-bold text-green-700">₹{Math.floor(instructorStats.totalRevenue * 0.3).toLocaleString()}</div>
                    <p className="text-sm text-green-600 mt-1">+12% from last month</p>
                  </div>
                  <div className="bg-gradient-to-r from-blue-50 to-blue-100 p-6 rounded-lg border border-blue-200">
                    <h4 className="font-semibold text-blue-800 mb-2">New Enrollments</h4>
                    <div className="text-3xl font-bold text-blue-700">{Math.floor(instructorStats.totalStudents * 0.1)}</div>
                    <p className="text-sm text-blue-600 mt-1">+8% from last month</p>
                  </div>
                  <div className="bg-gradient-to-r from-purple-50 to-purple-100 p-6 rounded-lg border border-purple-200">
                    <h4 className="font-semibold text-purple-800 mb-2">Course Completion</h4>
                    <div className="text-3xl font-bold text-purple-700">78%</div>
                    <p className="text-sm text-purple-600 mt-1">+5% improvement</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Course Upload Modal */}
      {showUploadModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-3xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b flex justify-between items-center">
              <h2 className="text-xl font-bold text-gray-900">Upload New Course</h2>
              <button onClick={() => setShowUploadModal(false)} className="text-gray-500 hover:text-gray-700 transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Course Title *</label>
                  <input 
                    type="text" 
                    value={courseForm.title}
                    onChange={(e) => setCourseForm({...courseForm, title: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                    placeholder="Enter course title" 
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Price (₹) *</label>
                  <input 
                    type="number" 
                    value={courseForm.price}
                    onChange={(e) => setCourseForm({...courseForm, price: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                    placeholder="99" 
                    min="1"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Description *</label>
                <textarea 
                  value={courseForm.desc}
                  onChange={(e) => setCourseForm({...courseForm, desc: e.target.value})}
                  className="w-full border border-gray-300 rounded-lg px-3 py-2 h-24 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                  placeholder="Course description"
                  required
                ></textarea>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Duration</label>
                  <input 
                    type="text" 
                    value={courseForm.time}
                    onChange={(e) => setCourseForm({...courseForm, time: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                    placeholder="8h 30m" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
                  <select 
                    value={courseForm.cat}
                    onChange={(e) => setCourseForm({...courseForm, cat: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                  >
                    <option value="development">Development</option>
                    <option value="design">Design</option>
                    <option value="business">Business</option>
                    <option value="ai">AI/Data Science</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Level</label>
                  <select 
                    value={courseForm.level}
                    onChange={(e) => setCourseForm({...courseForm, level: e.target.value})}
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                  >
                    <option value="Beginner">Beginner</option>
                    <option value="Intermediate">Intermediate</option>
                    <option value="Advanced">Advanced</option>
                  </select>
                </div>
              </div>

              {/* Video Upload Section */}
              <div className="bg-gray-50 p-4 rounded-lg">
                <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center">
                  <Video className="w-5 h-5 mr-2 text-blue-600" />
                  Course Videos ({courseForm.videos.length} videos)
                </h3>

                {/* Show existing videos */}
                {courseForm.videos.length > 0 && (
                  <div className="mb-4">
                    <h4 className="text-sm font-medium text-gray-700 mb-2">Added Videos</h4>
                    <div className="space-y-2">
                      {courseForm.videos.map((video, index) => (
                        <div key={index} className="bg-white p-3 rounded-lg border flex items-center justify-between">
                          <div className="flex-1">
                            <p className="text-sm font-medium text-gray-700">Video {index + 1}</p>
                            <p className="text-xs text-gray-500 truncate max-w-md">{video}</p>
                          </div>
                          <button
                            type="button"
                            onClick={() => removeVideo(index)}
                            className="bg-red-600 text-white px-2 py-1 rounded text-xs hover:bg-red-700 transition"
                          >
                            Remove
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                <div className="border-t pt-4">
                  <h4 className="text-sm font-medium text-gray-700 mb-3">Add Video</h4>
                  <div className="flex space-x-4 mb-4">
                    <button
                      type="button"
                      onClick={() => setCourseForm({...courseForm, videoType: 'link'})}
                      className={`flex items-center px-4 py-2 rounded-lg border transition-colors ${
                        courseForm.videoType === 'link' 
                          ? 'bg-blue-600 text-white border-blue-600' 
                          : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                      }`}
                    >
                      <Link className="w-4 h-4 mr-2" />
                      Video Link
                    </button>
                    <button
                      type="button"
                      onClick={() => setCourseForm({...courseForm, videoType: 'upload'})}
                      className={`flex items-center px-4 py-2 rounded-lg border transition-colors ${
                        courseForm.videoType === 'upload' 
                          ? 'bg-blue-600 text-white border-blue-600' 
                          : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                      }`}
                    >
                      <FileVideo className="w-4 h-4 mr-2" />
                      Upload Video
                    </button>
                  </div>

                  {courseForm.videoType === 'link' ? (
                    <div className="flex space-x-2">
                      <input 
                        type="url" 
                        value={courseForm.newVideoUrl}
                        onChange={(e) => setCourseForm({...courseForm, newVideoUrl: e.target.value})}
                        className="flex-1 border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors" 
                        placeholder="https://dropbox.com/s/xyz/video.mp4 or YouTube/Vimeo link" 
                      />
                      <button
                        type="button"
                        onClick={addVideoUrl}
                        className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition flex items-center"
                      >
                        <Plus className="w-4 h-4 mr-1" />
                        Add
                      </button>
                    </div>
                  ) : (
                    <div 
                      className={`border-2 border-dashed rounded-lg p-6 text-center transition-colors cursor-pointer ${
                        dragActive 
                          ? 'border-blue-500 bg-blue-50' 
                          : 'border-gray-300 hover:border-gray-400'
                      }`}
                      onDragEnter={handleDrag}
                      onDragLeave={handleDrag}
                      onDragOver={handleDrag}
                      onDrop={handleDrop}
                      onClick={() => document.getElementById('videoUpload').click()}
                    >
                      <input 
                        type="file" 
                        accept="video/*" 
                        onChange={(e) => e.target.files[0] && handleVideoUpload(e.target.files[0])}
                        className="hidden" 
                        id="videoUpload"
                      />
                      <FileVideo className="w-8 h-8 mx-auto mb-2 text-gray-400" />
                      <p className="text-gray-600 font-medium">
                        {dragActive ? 'Drop video here' : 'Click to upload or drag and drop'}
                      </p>
                      <p className="text-sm text-gray-500 mt-1">MP4, MOV, AVI up to 500MB</p>
                    </div>
                  )}
                </div>
              </div>

              {/* Fixed Thumbnail Upload */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Course Thumbnail</label>
                <div 
                  className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors cursor-pointer ${
                    thumbnailDragActive 
                      ? 'border-blue-500 bg-blue-50' 
                      : 'border-gray-300 hover:border-gray-400'
                  }`}
                  onDragEnter={handleThumbnailDrag}
                  onDragLeave={handleThumbnailDrag}
                  onDragOver={handleThumbnailDrag}
                  onDrop={handleThumbnailDrop}
                  onClick={() => document.getElementById('thumbnailUpload').click()}
                >
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={(e) => e.target.files[0] && handleThumbnailUpload(e.target.files[0])}
                    className="hidden" 
                    id="thumbnailUpload"
                  />
                  <Upload className="w-8 h-8 mx-auto mb-2 text-gray-400" />
                  <p className="text-gray-500 font-medium">
                    {thumbnailDragActive ? 'Drop image here' : 'Click to upload or drag and drop'}
                  </p>
                  <p className="text-xs text-gray-400 mt-1">PNG, JPG, GIF up to 10MB</p>
                </div>
                {courseForm.img !== 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop' && (
                  <p className="text-sm text-green-600 mt-2 flex items-center">
                    <Upload className="w-4 h-4 mr-1" />
                    Thumbnail uploaded successfully!
                  </p>
                )}
              </div>

              <div className="flex gap-3 pt-4">
                <button type="submit" className="flex-1 bg-blue-600 text-white py-3 rounded-lg hover:bg-blue-700 font-medium transition-colors">
                  Upload Course
                </button>
                <button 
                  type="button"
                  onClick={() => setShowUploadModal(false)}
                  className="px-6 bg-gray-200 text-gray-700 py-3 rounded-lg hover:bg-gray-300 transition-colors"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Edit Modal */}
      {showEditModal && <EditModal />}

      {/* Course View Modal */}
      {showCourseModal && selectedCourse && (
        <CourseModal course={selectedCourse} onClose={() => setShowCourseModal(false)} />
      )}
    </div>
  );
};

export default InstructorPage;
